  payload.sun_azimuth ??
  payload.heartRate ??
  payload.Value ??
  0
);

const pulses = Number(payload.pulses ?? 0);
const intensity = Number(payload.intensity ?? 0);
const duration = Number(payload.duration ?? 0);
const interval = Number(payload.interval ?? 0);

// feedback range ID from DB
const fbRangeID = Number(payload.fbRangeID ?? 0);

// 4. בניית מערך פרמטרים עבור Postgres
const params = [
  userId,
  watchId,
  phoneId,
  sensorName,
  alertGiven,
  value,
  pulses,
  intensity,
  duration,
  interval,
  fbRangeID
];

// 5. החזרת items בצורה ש-n8n רוצה
return [
