const sunAzimuthRanges = $input.all().map(item => item.json);

// 2. Get sun_azimuth from AssignPayloadToOriginalPayload node
const currentAzimuth =
  $node["AssignPayloadToOriginalPayload"].json.originalPayload.sun_azimuth;

function map(value, inMin, inMax, outMin, outMax) {
  if (inMin === inMax) return outMin;
  return outMin + (value - inMin) * (outMax - outMin) / (inMax - inMin);
}

const payload = {
  monitoringType: "SunAzimuth",
  sun_azimuth: currentAzimuth,
  pulses: 0,
  intensity: 0,
  duration: 0,
  interval: 0,
  fbRangeID: null,
  alertGiven: "no",
  message: ""
};

if (Array.isArray(sunAzimuthRanges) && sunAzimuthRanges.length > 0) {
  let matched = false;

  for (const range of sunAzimuthRanges) {
    const minAz = Number(range.minvalue);
    const maxAz = Number(range.maxvalue);

    if (!Number.isFinite(minAz) || !Number.isFinite(maxAz)) continue;
    if (currentAzimuth < minAz || currentAzimuth > maxAz) continue;

    matched = true;

    const minPulses = Number(range.minpulses ?? 0);
    const maxPulses = Number(range.maxpulses ?? minPulses);
    const minIntensity = Number(range.minintensity ?? 0);
    const maxIntensity = Number(range.maxintensity ?? minIntensity);
    const minDuration = Number(range.minduration ?? 0);
    const maxDuration = Number(range.maxduration ?? minDuration);
    const minInterval = Number(range.mininterval ?? 0);
    const maxInterval = Number(range.maxinterval ?? minInterval);

    payload.pulses = Math.round(
      map(currentAzimuth, minAz, maxAz, minPulses, maxPulses)
    );
    payload.intensity = Math.round(
      map(currentAzimuth, minAz, maxAz, minIntensity, maxIntensity)
    );
    payload.duration = Math.round(
      map(currentAzimuth, minAz, maxAz, minDuration, maxDuration)
    );
    payload.interval = Math.round(
      map(currentAzimuth, minAz, maxAz, minInterval, maxInterval)
    );

    payload.fbRangeID = Number(range.id);
    payload.alertGiven = payload.pulses > 0 ? "yes" : "no";
    payload.message =
      "✅ Mapped SunAzimuth range with proportional vibration settings.";
    break;
  }

  if (!matched) {
    payload.message = "⛔ No SunAzimuth match found in DB.";
  }
} else {
  payload.message = "⚠️ No mappings retrieved from database for SunAzimuth.";
}

const originalPayload = {
  sun_azimuth: currentAzimuth
};

return [
  {
    json: {
      payload,
      originalPayload
    }
  }
];

