};

for (const m of mappings) {
    const minHR = parseFloat(m.minvalue);
    const maxHR = parseFloat(m.maxvalue);

    if (heartRate >= minHR && heartRate <= maxHR) {
        feedback.intensity = Math.round(map(heartRate, minHR, maxHR, m.minintensity, m.maxintensity));
        feedback.pulses = Math.round(map(heartRate, minHR, maxHR, m.minpulses, m.maxpulses));
        feedback.duration = Math.round(map(heartRate, minHR, maxHR, m.minduration, m.maxduration));
        feedback.interval = Math.round(map(heartRate, minHR, maxHR, m.mininterval, m.maxinterval));
        feedback.fbRangeID = parseInt(m.id);
        feedback.alertGiven = feedback.pulses > 0 ? "yes" : "no";
        break;
    }
}
return [{ json: feedback  }];

// Extract database readings
const readings = items.map(item => parseFloat(item.json.value)).filter(v => !isNaN(v));

// Extract raw sensor input from Webhook
const rawValue = parseFloat($('Webhook').item.json.body.Value || 0);

// Outlier definition
const isOutlier = (v) => v < 40 || v > 220;

// Add raw value if it's valid
if (!isOutlier(rawValue)) {
    readings.push(rawValue);
}

let smoothed = rawValue; // Default to raw if no history
if (readings.length > 0) {
    const total = readings.reduce((sum, val) => sum + val, 0);
    smoothed = total / readings.length;
}

return [
  {
    json: {
      heartRate: smoothed,
      rawValue: rawValue
    }
  }
];

// Get the raw text from the AI (it might be in .output or .text)
const aiOutput = $input.first().json.output || $input.first().json.text || "";

// 1. If it's already an object, return it directly
if (typeof aiOutput === 'object') {
  return [{ json: aiOutput }];
}

// 2. If it's a string, use Regex to find the JSON object inside it
// This ignores text like "Here is your JSON:"
const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error("No JSON found in AI response. Raw output: " + aiOutput);
}

try {
  const parsedData = JSON.parse(jsonMatch[0]);
  return [{ json: parsedData }];
} catch (e) {
  throw new Error("Found JSON-like text but failed to parse: " + jsonMatch[0]);
}

